#include<bits/stdc++.h>
using namespace std;
long long kisten(int k,string x){
	stack<int> st;
	long long ans=0;
	for(int i=x.size()-1;i>=0;i--){
		if(x[i]>='A'&&x[i]<='Z'){
			st.push(int(x[i]-'A')+10);
		}
		else{
			st.push(int(x[i]-'0'));
		}
	}
	while(st.size()){
		ans+=(st.top())*(pow(k,st.size()-1));
		st.pop();
	}
	return ans;
}
int main(void){
	int n,k;
	string m;
	cin>>k;
	for(int i=0;i<k;i++){
		cin>>n>>m;
		cout<<kisten(n,m)<<endl;
	}
    return false;
}
